92	  it.todo("claim: cursed sword → cap 2000 based on unmodified insurance value (modifiers do not raise cap)");
93	  it.todo("claim: sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only, not insurance sum)");
94	
95	  // --- Claim: cap exhaustion across successive claims ---
