const unitPrice = (type: string): number => BASE_PREMIUMS[type] ?? 0;

const basePremium = (items: Item[]): number => {
  const mainTotal = items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + unitPrice(item.type), 0);

  const componentTotal = [...countByType(items.filter(isComponent))].reduce(
    (sum, [type, count]) => sum + componentBasePremium(count, unitPrice(type)),
    0
  );

  return mainTotal + componentTotal;
};

